import sys
import json


def compute(numbers):
    return {
        "count": len(numbers),
        "mean": sum(numbers) / len(numbers),
        "min": min(numbers),
        "max": max(numbers),
    }


def main():
    use_json = "--json" in sys.argv
    if use_json:
        sys.argv.remove("--json")

    path = sys.argv[1]
    numbers = [float(line) for line in open(path) if line.strip()]
    s = compute(numbers)

    if use_json:
        print(json.dumps(s))
    else:
        print(f"count: {s['count']}")
        print(f"mean: {s['mean']:.2f}")
        print(f"min: {s['min']}")
        print(f"max: {s['max']}")

